const raw = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;
if (!body.job_id) throw new Error('Payload missing: job_id');
if (!Array.isArray(body.clip_prompts) || body.clip_prompts.length < 1) throw new Error('Payload must have clip_prompts array');
return [{ json: {
  job_id: body.job_id,
  topic: body.topic,
  title: body.title,
  hashtags: body.hashtags,
  narration: body.narration,
  clip_prompts: body.clip_prompts,
  audio_path: body.audio_path,
  subs_path: body.subs_path,
  audio_duration: body.audio_duration,
  subtitle_chunks: body.subtitle_chunks,
  word_timings: body.word_timings,
  sheet_row: body.sheet_row || null,
  start_time: body.start_time || Date.now(),
  bgm_path: body.bgm_path || null,
  negative_prompts: body.negative_prompts || [],
  highlight_keywords: body.highlight_keywords || []
} }];

const { execSync } = require('child_process');
const fs = require('fs');

const data      = $input.first().json;
const jobId     = data.job_id;
const videoUrls = data.video_urls;
const N         = videoUrls.length;

const n8nIn  = '/data/ffmpeg/input';
const n8nOut = '/data/ffmpeg/output';
const contIn = '/ffmpeg/input';
const contOut= '/ffmpeg/output';

if (!fs.existsSync(n8nIn))  fs.mkdirSync(n8nIn,  { recursive: true });
if (!fs.existsSync(n8nOut)) fs.mkdirSync(n8nOut, { recursive: true });

function run(cmd, timeoutMs) {
  const t = timeoutMs || 120000;
  console.log('CMD: ' + cmd.slice(0, 200));
  let out = '';
  try { out = execSync(cmd, { encoding: 'utf-8', timeout: t }); }
  catch(e) { out = (e.stdout || '') + (e.stderr || ''); }
  return out.toString();
}

// STEP 1: Download clips
for (let i = 0; i < N; i++) {
  run('docker exec ffmpeg-runner curl -sL -o "' + contIn + '/' + jobId + '_clip' + i + '.mp4" "' + videoUrls[i] + '"', 60000);
}

// STEP 2: Normalize to 1080x1920
for (let i = 0; i < N; i++) {
  run('docker exec ffmpeg-runner ffmpeg -y -i "' + contIn + '/' + jobId + '_clip' + i + '.mp4" -vf "scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black" -r 24 -c:v libx264 -crf 20 -preset fast -an "' + contIn + '/' + jobId + '_clip' + i + '_norm.mp4"', 120000);
}

// STEP 3: XFADE transitions
let withTransitions;
if (N === 1) {
  withTransitions = contIn + '/' + jobId + '_clip0_norm.mp4';
} else {
  const inputs = Array.from({length:N}, (_,i) => '-i "' + contIn + '/' + jobId + '_clip' + i + '_norm.mp4"').join(' ');
  let xf = '';
  let prev = '[0:v]';
  for (let i = 1; i < N; i++) {
    const o = (i === N-1) ? '[vout]' : '[x'+i+']';
    xf += prev + '['+i+':v]xfade=transition=fade:duration=0.3:offset=' + (i*4.7).toFixed(1) + o + ';';
    prev = o;
  }
  run('docker exec ffmpeg-runner ffmpeg -y ' + inputs + ' -filter_complex "' + xf.slice(0,-1) + '" -map "[vout]" -c:v libx264 -crf 20 -preset fast "' + contIn + '/' + jobId + '_xfade.mp4"', 300000);
  withTransitions = contIn + '/' + jobId + '_xfade.mp4';
}

// STEP 4: ASS subtitle with CYAN keyword highlights
// ASS BGR color: &HFFFF00& = B=FF,G=FF,R=00 = Cyan RGB(0,255,255)
const hlWords = (data.highlight_keywords || []).map(w => w.toLowerCase());
const narTxt  = (data.narration || '').replace(/"/g, "'").replace(/\n/g, ' ');

function esc(s) { return s.replace(/[.+?^${}()|[\]\\*]/g, '\\$&'); }
function addHighlights(text) {
  let r = text;
  hlWords.forEach(word => {
    const re = new RegExp('(' + esc(word) + ')', 'gi');
    var _bs = String.fromCharCode(92); r = r.replace(re, '{' + _bs + 'c&HFF9600&}$1{' + _bs + 'c&HFFFFFF&}');
  });
  return r;
}
const hlText = addHighlights(narTxt);

const assContent =
  '[Script Info]\nScriptType: v4.00+\nPlayResX: 1080\nPlayResY: 1920\n\n' +
  '[V4+ Styles]\n' +
  'Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding\n' +
  'Style: Caption,Liberation Sans,52,&H00FFFFFF,&H000000FF,&H00000000,&H80000000,-1,0,1,3,0,7,60,60,470,1\n\n' +
  '[Events]\nFormat: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text\n' +
  'Dialogue: 0,0:00:00.00,0:01:00.00,Caption,,0,0,0,,' + hlText + '\n';

fs.writeFileSync(n8nIn + '/' + jobId + '.ass', assContent, 'utf8');
console.log('ASS written. Highlights: ' + hlWords.join(', '));

// STEP 5: Check assets
const logoPath = '/ffmpeg/config/icon/logo.png';
const tickPath = '/ffmpeg/config/icon/Blue verification badge emblem.png';
const bgmDir   = '/ffmpeg/config/bgm';

const hasLogo = run('docker exec ffmpeg-runner test -f "' + logoPath + '" && echo OK').includes('OK');
const hasTick = run('docker exec ffmpeg-runner test -f "' + tickPath + '" && echo OK').includes('OK');

// Narration audio from Stage 1 — FIX: was completely ignored before
let narFile = null;
if (data.audio_path) {
  narFile = data.audio_path.replace('/data/ffmpeg', '/ffmpeg');
  if (!run('docker exec ffmpeg-runner test -f "' + narFile + '" && echo OK').includes('OK')) {
    console.log('Narration not found: ' + narFile);
    narFile = null;
  }
}

// BGM
let bgmFile = data.bgm_path ? data.bgm_path.replace('/data/ffmpeg', '/ffmpeg') : null;
if (!bgmFile) {
  const ls = run('docker exec ffmpeg-runner ls "' + bgmDir + '" 2>/dev/null').split('\n');
  const mp3 = ls.find(f => f.trim().endsWith('.mp3'));
  if (mp3) bgmFile = bgmDir + '/' + mp3.trim();
}
const hasBgm = !!(bgmFile && run('docker exec ffmpeg-runner test -f "' + bgmFile + '" && echo OK').includes('OK'));
console.log('narFile=' + narFile + ' hasBgm=' + hasBgm);

// STEP 6: Build input list with tracked indices
const inp   = ['-i "' + withTransitions + '"'];
const logoI = hasLogo ? inp.push('-i "' + logoPath + '"') - 1 : -1;
const tickI = hasTick ? inp.push('-i "' + tickPath + '"') - 1 : -1;
const narI  = narFile  ? inp.push('-i "' + narFile  + '"') - 1 : -1;
const bgmI  = hasBgm   ? inp.push('-i "' + bgmFile  + '"') - 1 : -1;

// STEP 7: Video filter chain
let lbl = 0;
let vf  = '';
let cur = '0:v';

if (hasLogo) {
  vf += '[' + logoI + ':v]scale=110:110,format=rgba[lg];[' + cur + '][lg]overlay=x=40:y=293:format=auto[vb' + lbl + ']';
  cur = 'vb' + lbl; lbl++;
}

vf += (vf ? ';' : '') + '[' + cur + "]drawtext=text='SchrodingersCat':fontcolor=white:fontsize=52:x=178:y=308:bordercolor=black:borderw=3[vb" + lbl + ']';
cur = 'vb' + lbl; lbl++;

if (hasTick) {
  vf += ';[' + tickI + ":v]crop='min(iw,ih)':'min(iw,ih)',scale=72:72,format=rgba[tk];[" + cur + '][tk]overlay=x=600:y=300:format=auto[vb' + lbl + ']';
  cur = 'vb' + lbl; lbl++;
}

vf += ';[' + cur + "]drawtext=text='@SchrodingersCat':fontcolor=white:fontsize=34:x=178:y=377:bordercolor=black:borderw=2[vb" + lbl + ']';
cur = 'vb' + lbl; lbl++;

vf += ";[" + cur + "]subtitles=filename='" + contIn + '/' + jobId + ".ass'[outv]";

// STEP 8: Audio — narration (full) + BGM (25%) mixed
let afilters = '';
let amap     = '-an';

if (narFile && hasBgm) {
  afilters = ';[' + narI + ':a]volume=1.0[nar];[' + bgmI + ':a]volume=0.25[bgm];[nar][bgm]amix=inputs=2:duration=first:dropout_transition=2[aout]';
  amap     = '-map "[aout]"';
} else if (narFile) {
  afilters = ';[' + narI + ':a]aformat=sample_fmts=fltp[aout]';
  amap     = '-map "[aout]"';
} else if (hasBgm) {
  afilters = ';[' + bgmI + ':a]volume=0.85[aout]';
  amap     = '-map "[aout]"';
}

const fullFilter = vf + afilters;
const dur = data.audio_duration ? Math.ceil(data.audio_duration) + 2 : 30;
const hasAudio = amap !== '-an';

const cmd =
  'docker exec ffmpeg-runner ffmpeg -y ' + inp.join(' ') +
  ' -filter_complex "' + fullFilter + '" -map "[outv]" ' + amap +
  ' -c:v libx264 -crf 18 -preset fast' +
  (hasAudio ? ' -c:a aac -b:a 192k' : '') +
  ' -t ' + dur + ' "' + contOut + '/' + jobId + '_final.mp4" && echo FINAL_OK';

const result = run(cmd, 900000);
if (!result.includes('FINAL_OK')) throw new Error('Final render failed: ' + result.slice(-800));

const finalPath = n8nOut + '/' + jobId + '_final.mp4';
if (!fs.existsSync(finalPath)) throw new Error('Output missing: ' + finalPath);

return [{ json: { ...data, final_video_path: finalPath, output_filename: jobId + '_final.mp4' }}];

const fs = require('fs');
const item = $input.first().json;
const filePath = item.final_video_path;

if (!fs.existsSync(filePath)) throw new Error('Final video not found: ' + filePath);

// Read in 10MB chunks to avoid single huge allocation
const CHUNK = 10 * 1024 * 1024;
const stat  = fs.statSync(filePath);
const total = stat.size;
const fd    = fs.openSync(filePath, 'r');
const parts = [];
let pos = 0;
while (pos < total) {
  const len = Math.min(CHUNK, total - pos);
  const buf = Buffer.allocUnsafe(len);
  fs.readSync(fd, buf, 0, len, pos);
  parts.push(buf.toString('base64'));
  pos += len;
}
fs.closeSync(fd);
const b64 = parts.join('');

return [{
  json: item,
  binary: {
    data: {
      data:          b64,
      mimeType:      'video/mp4',
      fileName:      item.output_filename,
      fileExtension: 'mp4'
    }
  }
}];

const driveNode    = $('Upload Animation to Drive').first().json;
const assembleData = $('Assemble Video').first().json;
const fileId = driveNode.id;

// assembleData spreads the full original payload (including sheet_row, topic, title, etc.)
// Works for both Webhook path and Manual Trigger path
const videoUrl      = 'https://drive.google.com/uc?export=download&id=' + fileId;
const renderTimeSec = Math.round((Date.now() - assembleData.start_time) / 1000);

console.log('Stage 2 complete. Job: ' + assembleData.job_id + ', Drive file: ' + fileId + ', Time: ' + renderTimeSec + 's');

return [{ json: {
  job_id:              assembleData.job_id,
  topic:               assembleData.topic,
  title:               assembleData.title,
  video_url:           videoUrl,
  drive_file_id:       fileId,
  render_time_seconds: renderTimeSec,
  sheet_row:           assembleData.sheet_row,
  status:              'stage2_complete'
} }];

const assemble   = $('Assemble Video').first().json;
const stage2Done = $('Stage 2 Done').first().json;
return [{ json: {
  job_id:           stage2Done.job_id,
  title:            stage2Done.title,
  topic:            stage2Done.topic,
  narration:        assemble.narration || '',
  description:      (assemble.narration || stage2Done.topic).slice(0, 500),
  hashtags:         assemble.hashtags || '',
  final_video_path: assemble.final_video_path,
  output_filename:  assemble.output_filename,
  drive_file_id:    stage2Done.drive_file_id,
  drive_video_url:  stage2Done.video_url,
  sheet_row:        stage2Done.sheet_row,
  callback_url:     null
}}];

const https = require('https');
const data = $input.first().json;
const apiKey = $env.WAVESPEED_API_KEY;
const clipPrompts = data.clip_prompts;
const negativePrompts = data.negative_prompts || [];
const defaultNeg = 'text, letters, alphabet, messy, distorted, watermark';

if (!Array.isArray(clipPrompts) || clipPrompts.length === 0)
  throw new Error('No clip_prompts in payload');

const audioDuration = data.audio_duration || 30;
const clipsNeeded   = clipPrompts.length; // Stage 1 already calculated exact count (6 for 30s)
console.log('Audio duration: ' + audioDuration.toFixed(1) + 's → generating ' + clipsNeeded + ' clips (5s each)');

function apiPost(body) {
  return new Promise((resolve, reject) => {
    const buf = Buffer.from(JSON.stringify(body));
    const req = https.request({
      hostname: 'api.wavespeed.ai',
      path: '/api/v3/bytedance/seedance-v1-lite-t2v-720p',
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + apiKey,
        'Content-Type': 'application/json',
        'Content-Length': buf.length
      }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch(e) { reject(new Error('Bad JSON from Wavespeed')); }
      });
    });
    req.on('error', reject);
    req.write(buf);
    req.end();
  });
}

const submitPromises = [];
for (let i = 0; i < clipsNeeded; i++) {
  submitPromises.push(
    apiPost({
      prompt:          clipPrompts[i],
      negative_prompt: negativePrompts[i] || defaultNeg,
      aspect_ratio:    '9:16',
      duration:        5,
      seed:            -1
    })
  );
}

const results = await Promise.all(submitPromises);

const task_ids = [];
for (let i = 0; i < results.length; i++) {
  const r = results[i];
  if (!r.data || !r.data.id) throw new Error('Wavespeed submit failed: ' + JSON.stringify(r));
  task_ids.push(r.data.id);
}

return [{ json: {
  ...data,
  task_ids,
  clips_count: clipsNeeded,
  video_urls:  new Array(clipsNeeded).fill(null),
  poll_attempt: 0,
  all_done:    false
}}];

const https = require('https');
const data = $input.first().json;
const apiKey = $env.WAVESPEED_API_KEY;
const task_ids   = data.task_ids;
const video_urls = [...(data.video_urls || [null, null, null])];
const attempt    = (data.poll_attempt || 0) + 1;

console.log('--- Poll attempt #' + attempt + ' ---');

function apiGet(taskId) {
  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'api.wavespeed.ai',
      path: '/api/v3/predictions/' + taskId + '/result',
      method: 'GET',
      headers: { 'Authorization': 'Bearer ' + apiKey }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const raw = Buffer.concat(chunks).toString();
        try { resolve(JSON.parse(raw)); }
        catch(e) { reject(new Error('Non-JSON from Wavespeed status [HTTP ' + res.statusCode + ']: ' + raw.slice(0,200))); }
      });
    });
    req.on('error', reject);
    req.end();
  });
}

// Check each clip that is not yet complete
for (let i = 0; i < task_ids.length; i++) {
  if (video_urls[i] !== null) {
    console.log('Clip ' + i + ' already done, skipping');
    continue;
  }

  const r = await apiGet(task_ids[i]);
  const status = (r.data && r.data.status) || 'unknown';
  console.log('Clip ' + i + ' [' + task_ids[i] + '] status: ' + status);

  if (status === 'completed') {
    const url = r.data.outputs && r.data.outputs[0];
    if (!url) throw new Error('Clip ' + i + ' completed but output URL missing');
    video_urls[i] = url;
    console.log('Clip ' + i + ' ready: ' + url);
  } else if (status === 'failed') {
    throw new Error('Clip ' + i + ' FAILED: ' + JSON.stringify(r.data));
  } else {
    console.log('Clip ' + i + ' still ' + status + ' – will retry in 20s');
  }
}

const all_done = video_urls.every(u => u !== null) ? 1 : 0;
const pending  = video_urls.filter(u => u === null).length;

if (all_done === 1) {
  console.log('All clips are ready! Proceeding to assembly.');
} else {
  console.log(pending + ' clip(s) still generating. Waiting 20s before next poll.');
}

return [{ json: {
  ...data,
  task_ids,
  video_urls,
  poll_attempt: attempt,
  all_done
}}];
